package com.google.gson.internal.reflect;
import com.google.gson.JsonIOException;
import com.google.gson.internal.GsonBuildConfig;
import java.lang.reflect.AccessibleObject;
import java.lang.reflect.Field;
import java.lang.reflect.Method;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Constructor;
import java.lang.reflect.InvocationTargetException;

import org.junit.jupiter.api.Test;

class ReflectionHelperTest {

  @Test
  void tryMakeAccessible_success() throws NoSuchMethodException {
    Constructor<String> constructor = String.class.getDeclaredConstructor(String.class);
    String result = ReflectionHelper.tryMakeAccessible(constructor);
    assertNull(result);
    assertTrue(constructor.canAccess(null));
  }

  @Test
  void tryMakeAccessible_failure() throws Exception {
    // Create a mock Constructor that throws exception on setAccessible(true)
    Constructor<?> constructor = mock(Constructor.class);
    doThrow(new SecurityException("Access denied")).when(constructor).setAccessible(true);
    when(constructor.toString()).thenReturn("mockConstructor");

    // We need to mock constructorToString static method call inside tryMakeAccessible.
    // Since constructorToString is static and in the same class, we cannot mock it easily with Mockito 3.
    // Instead, we rely on the actual constructorToString method by using a real Constructor.
    // So instead, create a spy on ReflectionHelper class to mock constructorToString.
    // But since constructorToString is static, Mockito 3 cannot mock static methods without inline mock maker.
    // So we will not mock constructorToString, but rely on the exception message and the returned string containing exception message.

    String message = ReflectionHelper.tryMakeAccessible(constructor);

    assertNotNull(message);
    assertTrue(message.contains("Failed making constructor"));
    assertTrue(message.contains("Access denied"));
  }
}
